INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fbfdff39-13cd-4473-9ac1-850f14aaf58e',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebGL Graphics Pipeline — Optimizing Vertex Processing and Fragment Shading$escape$,
  $escape$WebGL's graphics pipeline involves several stages, including vertex processing, rasterization, fragment shading, and output merger. Vertex processing occurs in the vertex shader, where attributes like position, normal, and texture coordinates are processed. The `gl.vertexAttribPointer` function is used to specify the format of the vertex attributes. Rasterization converts the processed vertices into fragments, which are then shaded in the fragment shader using the `gl.fragmentShader` function. To optimize the pipeline, consider using `gl.drawArrays` or `gl.drawElements` for drawing, and minimize the number of shader switches.$escape$,
  $escape$gl.vertexAttribPointer(0, 3, gl.FLOAT, false, 0, 0); gl.enableVertexAttribArray(0);$escape$,
  $escape$javascript$escape$,
