INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a4930775-7667-4eda-b0e5-826de75bda20',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebGL — Efficient Vertex Data Management with VAOs and VBOs$escape$,
  $escape$In WebGL, using Vertex Array Objects (VAOs) and Vertex Buffer Objects (VBOs) is crucial for efficient vertex data management. VAOs store the state of vertex attributes, while VBOs store the actual vertex data. By binding a VAO and then binding VBOs to specific attribute indices, you can efficiently manage complex vertex data. Additionally, WebGL's core profile requires the use of VAOs and VBOs, making them essential for modern WebGL development. When working with textures, be mindful of the limited number of texture units available, typically between 8 and 32, depending on the hardware.$escape$,
  $escape$const vao = gl.createVertexArray(); gl.bindVertexArray(vao); const vbo = gl.createBuffer(); gl.bindBuffer(gl.ARRAY_BUFFER, vbo); gl.bufferData(gl.ARRAY_BUFFER, new Float32Array(vertices), gl.STATIC_DRAW);$escape$,
  $escape$javascript$escape$,
