INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5a3c2ab9-5a25-4bfd-9232-d3b249acb274',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebGL Post-Processing: Implementing Bloom with Framebuffers$escape$,
  $escape$WebGL post-processing techniques like bloom, depth of field, and tone mapping can significantly enhance the visual quality of graphics. To implement bloom in WebGL, we can utilize framebuffers to render the scene to a texture, then apply a threshold and blur to create the bloom effect. We start by creating a framebuffer with a texture attachment, then bind it and render the scene. The resulting texture is then used as input for the bloom shader, which applies the necessary threshold and blur operations. This approach allows for efficient and high-quality bloom effects in WebGL applications.$escape$,
  $escape$gl.bindFramebuffer(gl.FRAMEBUFFER, framebuffer); gl.framebufferTexture2D(gl.FRAMEBUFFER, gl.COLOR_ATTACHMENT0, gl.TEXTURE_2D, texture, 0);$escape$,
  $escape$javascript$escape$,
